package main

import (
	"html/template"
	"net/http"
)

// Define a struct to hold the data for the template
type SearchPageData struct {
	Keyword string
}

// HandleProductSearch handles the product search results page with analytics support.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Define the HTML template
	const tpl = `
<!DOCTYPE html>
<html>
<head>
	<title>Product Search Results</title>
</head>
<body>
	<h2>Search Results: {{.Keyword}}</h2>
</body>
</html>`

	// Parse the template
	tmpl, err := template.New("search").Parse(tpl)
	if err != nil {
		// Handle template parsing error
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	// Execute the template with the keyword data
	data := SearchPageData{Keyword: keyword}
	err = tmpl.Execute(w, data)
	if err != nil {
		// Handle template execution error
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}
}

