package main

import (
    "html"
    "net/http"
    "strings"
)

// HandleProductSearch handles the product search results page.
// It reads the 'keyword' query parameter and displays it in the page title.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
    // Set the content type to HTML
    w.Header().Set("Content-Type", "text/html; charset=utf-8")

    // Retrieve the 'keyword' query parameter
    keyword := r.URL.Query().Get("keyword")

    // Sanitize the keyword to prevent XSS (Cross-Site Scripting) attacks
    // html.EscapeString converts characters like <, >, &, " to their HTML entities
    safeKeyword := html.EscapeString(keyword)

    // Construct the HTML response
    // Using a strings.Builder for efficient string concatenation
    var htmlBuilder strings.Builder

    // Write the HTML structure
    htmlBuilder.WriteString("<!DOCTYPE html>\n")
    htmlBuilder.WriteString("<html lang=\"en\">\n")
    htmlBuilder.WriteString("<head>\n")
    htmlBuilder.WriteString("    <meta charset=\"UTF-8\">\n")
    htmlBuilder.WriteString("    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n")
    htmlBuilder.WriteString("    <title>Product Search Results</title>\n")
    htmlBuilder.WriteString("    <style>\n")
    htmlBuilder.WriteString("        body { font-family: sans-serif; margin: 40px; }\n")
    htmlBuilder.WriteString("        h2 { color: #333; border-bottom: 2px solid #eee; padding-bottom: 10px; }\n")
    htmlBuilder.WriteString("    </style>\n")
    htmlBuilder.WriteString("</head>\n")
    htmlBuilder.WriteString("<body>\n")

    // Display the search keyword in the page title area as requested
    // Format: <h2>Search Results: [keyword]</h2>
    htmlBuilder.WriteString("    <h2>Search Results: ")
    htmlBuilder.WriteString(safeKeyword)
    htmlBuilder.WriteString("</h2>\n")

    // Add a placeholder for search results content
    htmlBuilder.WriteString("    <div id=\"results\">\n")
    htmlBuilder.WriteString("        <p>Displaying products matching the query...</p>\n")
    htmlBuilder.WriteString("    </div>\n")
    htmlBuilder.WriteString("</body>\n")
    htmlBuilder.WriteString("</html>")

    // Write the generated HTML to the response writer
    w.Write([]byte(htmlBuilder.String()))
}

func main() {
    // Register the handler function to the /search endpoint
    http.HandleFunc("/search", HandleProductSearch)

    // Start the HTTP server on port 8080
    // Using a closure to handle server startup errors gracefully
    err := http.ListenAndServe(":8080", nil)
    if err != nil {
        // Log the error to standard output if the server fails to start
        // In a production environment, this would be logged to a proper logging system
        panic("Server failed to start: " + err.Error())
    }
}

