package main

import (
    "html"
    "net/http"
    "strings"
)

// HandleProductSearch handles the product search results page request.
// It retrieves the 'keyword' query parameter and displays it in the page title.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
    // Set the response content type to HTML
    w.Header().Set("Content-Type", "text/html; charset=utf-8")

    // Retrieve the 'keyword' query parameter from the URL
    keyword := r.URL.Query().Get("keyword")

    // Sanitize the keyword to prevent XSS attacks using html.EscapeString
    safeKeyword := html.EscapeString(keyword)

    // Construct the HTML response
    // Using a strings.Builder for efficient string concatenation
    var builder strings.Builder

    // HTML structure start
    builder.WriteString("<!DOCTYPE html>\n")
    builder.WriteString("<html lang=\"en\">\n")
    builder.WriteString("<head>\n")
    builder.WriteString("    <meta charset=\"UTF-8\">\n")
    builder.WriteString("    <meta name=\"viewport\" content=\"width=device-width, initial-scale=1.0\">\n")
    builder.WriteString("    <title>Product Search Results</title>\n")
    builder.WriteString("    <style>\n")
    builder.WriteString("        body { font-family: sans-serif; margin: 40px; }\n")
    builder.WriteString("        h2 { color: #333; border-bottom: 2px solid #eee; padding-bottom: 10px; }\n")
    builder.WriteString("    </style>\n")
    builder.WriteString("</head>\n")
    builder.WriteString("<body>\n")

    // Main content: Search Results title with the keyword
    builder.WriteString("    <h2>Search Results: ")
    builder.WriteString(safeKeyword)
    builder.WriteString("</h2>\n")

    // Placeholder for actual search results list
    builder.WriteString("    <div id=\"results\">\n")
    builder.WriteString("        <!-- Product list would be rendered here -->\n")
    builder.WriteString("    </div>\n")

    builder.WriteString("</body>\n")
    builder.WriteString("</html>")

    // Write the constructed HTML to the response writer
    w.Write([]byte(builder.String()))
}

func main() {
    // Register the handler function for the /search endpoint
    http.HandleFunc("/search", HandleProductSearch)

    // Start the HTTP server on port 8080
    // Using a specific port as required for a runnable example
    port := ":8080"

    // Inform the user which port the server is listening on
    // (This is printed to the console, not the HTTP response)
    println("Server starting on http://localhost" + port)

    if err := http.ListenAndServe(port, nil); err != nil {
        // If the server fails to start, print the error and exit
        panic(err)
    }
}

