	"net/http"
)

// Define the HTML template as a constant string to avoid file I/O
const searchResultsTemplate = `<!DOCTYPE html>
<html>
<head>
	<title>Product Search Results</title>
</head>
<body>
	<h2>Search Results: {{ .Keyword }}</h2>
</body>
</html>`

// Define a struct to hold data for the template
type SearchPageData struct {
	Keyword string
}

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Parse the HTML template
	tmpl, err := template.New("search").Parse(searchResultsTemplate)
	if err != nil {
		// If there is an error parsing the template, send an internal server error
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	// Prepare the data for the template
	data := SearchPageData{
		Keyword: keyword,
	}

	// Execute the template with the data and write to the response
	err = tmpl.Execute(w, data)
	if err != nil {
		// If there is an error executing the template, we cannot send a response
		// as the header might already be written. Log the error if needed.
		return
	}
}

