    builder.WriteString("<title>Product Search Results</title>")
    builder.WriteString("</head>")
    builder.WriteString("<body>")

    // Display the search keyword in the page title area as requested
    builder.WriteString("<h2>Search Results: ")
    builder.WriteString(sanitizedKeyword)
    builder.WriteString("</h2>")

    // Close HTML document
    builder.WriteString("</body>")
    builder.WriteString("</html>")

    // Write the HTML string to the response writer
    w.Write([]byte(builder.String()))
}

