        h2 { color: #333; border-bottom: 2px solid #007bff; padding-bottom: 10px; }
        .meta { color: #666; font-size: 0.9em; margin-top: 20px; }
    </style>
</head>
<body>
    <div class="container">
        <h2>Search Results: {{.Keyword}}</h2>
        <p>Displaying results for your search query.</p>
        <div class="meta">
            Generated at: {{.Timestamp}}
        </div>
    </div>
</body>
</html>
`

// HandleProductSearch handles the HTTP request for product search
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set the content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Parse the query parameter 'keyword'
	keyword := r.URL.Query().Get("keyword")

	// Sanitize the keyword to prevent XSS attacks using html/template's automatic escaping
	// However, since we are using a simple string replacement for the title, 
	// we will use html/template for the entire rendering to ensure safety.

	// If the keyword is empty, set a default message
	if strings.TrimSpace(keyword) == "" {
		keyword = "No keyword provided"
	}

	// Prepare the data for the template
	data := PageData{
		Keyword: keyword,
	}

	// Parse the template
	tmpl, err := template.New("search").Parse(htmlTemplate)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	// Execute the template with the data
	// The template engine automatically escapes the Keyword string for HTML context
	err = tmpl.Execute(w, data)
	if err != nil {
		// Log the error (in a real application, use a logger)
		// For this snippet, we simply return an error response if execution fails
		http.Error(w, "Error rendering page", http.StatusInternalServerError)
	}
}

func main() {
	// Register the handler function
