package main

import (
	"html/template"
	"net/http"
)

// Define a template structure to safely render user input
const searchResultsTemplate = `<!DOCTYPE html>
<html>
<head>
	<title>Product Search Results</title>
</head>
<body>
	<h2>Search Results: {{.Keyword}}</h2>
</body>
</html>`

// TemplateData holds the data to be passed to the template
type TemplateData struct {
	Keyword string
}

func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Extract the keyword from URL query parameters
	keyword := r.URL.Query().Get("keyword")

	// Set the Content-Type header to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Parse the template
	tmpl, err := template.New("search").Parse(searchResultsTemplate)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	// Prepare the data with the user input
	data := TemplateData{
		Keyword: keyword,
	}

	// Execute the template with the data
	// The template engine automatically escapes the keyword to prevent XSS
	err = tmpl.Execute(w, data)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}
}

