        .no-results { color: #666; font-style: italic; margin-top: 20px; }
    </style>
</head>
<body>
    <div class="container">
        <h2>Search Results: {{.Keyword}}</h2>
        <div class="no-results">
            <p>No specific products found for "{{.Keyword}}".</p>
