// HandleProductSearch handles the product search results page request
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set the content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Retrieve the 'keyword' query parameter
	keyword := r.URL.Query().Get("keyword")

	// Sanitize the keyword to prevent XSS attacks by escaping HTML characters
	// We use html.EscapeString to ensure the input is safe to render in HTML
	safeKeyword := html.EscapeString(strings.TrimSpace(keyword))

	// If no keyword is provided, use a default message
	if safeKeyword == "" {
		safeKeyword = "No keyword provided"
	}

	// Prepare the data for the template
