package main

import (
	"html"
	"html/template"
	"net/http"
	"strings"
)

// PageData holds the data to be passed to the HTML template
type PageData struct {
	Keyword string
}

// HTML template string for the search results page
const tmpl = `
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Search Results: {{.Keyword}}</title>
    <style>
        body { font-family: sans-serif; margin: 2rem; }
        h2 { color: #333; border-bottom: 1px solid #ccc; padding-bottom: 0.5rem; }
        .no-results { color: #666; font-style: italic; }
    </style>
</head>
<body>
    <h2>Search Results: {{.Keyword}}</h2>
    <p>Displaying results for your search query.</p>
</body>
</html>
`

// HandleProductSearch handles the incoming HTTP request for product search
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set the response content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Parse the 'keyword' query parameter from the URL
	keyword := r.URL.Query().Get("keyword")

	// Sanitize the keyword to prevent XSS attacks
	// html.EscapeString converts characters like <, >, &, " to their HTML entities
	safeKeyword := html.EscapeString(strings.TrimSpace(keyword))

	// Prepare the data for the template
	data := PageData{
		Keyword: safeKeyword,
	}

	// Parse the template string
	t, err := template.New("search").Parse(tmpl)
	if err != nil {
		// If template parsing fails, return an internal server error
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	// Execute the template with the data and write to the response writer
	err = t.Execute(w, data)
	if err != nil {
		// Log the error (in a real application) and return an internal server error
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}
}

func main() {
	// Register the handler function for the /search path
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080
	// In a real production environment, the port should be configurable
	println("Server starting on http://localhost:8080/search")
	if err := http.ListenAndServe(":8080", nil); err != nil {
		panic(err)
	}
}

