package main

import (
    "html"
    "html/template"
    "net/http"
    "strings"
)

// HandleProductSearch handles the product search results page request.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
    // Set the content type to HTML
    w.Header().Set("Content-Type", "text/html; charset=utf-8")

    // Get the 'keyword' query parameter from the URL
    keyword := r.URL.Query().Get("keyword")

    // Sanitize the keyword to prevent XSS (Cross-Site Scripting) attacks.
    // While we use html/template which auto-escapes, sanitizing input is good practice.
    // We also trim whitespace.
    keyword = strings.TrimSpace(keyword)
    safeKeyword := html.EscapeString(keyword)

    // Define the HTML template
    const tmpl = `
    <!DOCTYPE html>
    <html lang="en">
    <head>
        <meta charset="UTF-8">
        <meta name="viewport" content="width=device-width, initial-scale=1.0">
        <title>Search Results</title>
        <style>
            body { font-family: sans-serif; margin: 20px; }
            h2 { color: #333; border-bottom: 2px solid #eee; padding-bottom: 10px; }
            .no-results { color: #666; font-style: italic; }
        </style>
    </head>
    <body>
        <h2>Search Results: {{.Keyword}}</h2>

        {{if .HasKeyword}}
            <p>Displaying results for: <strong>{{.Keyword}}</strong></p>
            <!-- Placeholder for actual search results logic -->
            <p class="no-results">No specific product data implemented for this demo.</p>
        {{else}}
            <p class="no-results">Please provide a keyword to search.</p>
        {{end}}
    </body>
    </html>
    `

    // Create a data structure to pass to the template
    data := struct {
        Keyword   string
        HasKeyword bool
    }{
        Keyword:   safeKeyword,
        HasKeyword: keyword != "",
    }

    // Parse and execute the template
    t, err := template.New("search").Parse(tmpl)
    if err != nil {
        http.Error(w, "Internal Server Error", http.StatusInternalServerError)
        return
    }

    err = t.Execute(w, data)
    if err != nil {
        // Log the error if you have a logger, for now we just ignore it 
        // as the response might already be partially written.
    }
}

func main() {
    // Register the handler function
    http.HandleFunc("/search", HandleProductSearch)

    // Start the server
    // Using a standard port
    port := ":8080"
    println("Server starting on http://localhost" + port)
    if err := http.ListenAndServe(port, nil); err != nil {
        panic(err)
    }
}

