// HandleProductSearch handles the product search results page request.
// It retrieves the search keyword from the URL query parameter "keyword",
// sanitizes it, and renders an HTML page displaying the results.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set the content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Retrieve the 'keyword' query parameter
	keyword := r.URL.Query().Get("keyword")

	// Sanitize the keyword to prevent XSS attacks using html.EscapeString
	safeKeyword := html.EscapeString(keyword)

	// Define the HTML template structure
	const tmpl = `
	<!DOCTYPE html>
	<html lang="en">
	<head>
		<meta charset="UTF-8">
		<meta name="viewport" content="width=device-width, initial-scale=1.0">
		<title>Search Results</title>
		<style>
			body { font-family: sans-serif; margin: 2rem; }
			h2 { color: #333; border-bottom: 2px solid #eee; padding-bottom: 0.5rem; }
			.results { margin-top: 2rem; color: #666; }
		</style>
	</head>
	<body>
		<h2>Search Results: {{.Keyword}}</h2>
		<div class="results">
			<p>Displaying results for: <strong>{{.Keyword}}</strong></p>
