// PageData holds the data to be rendered in the HTML template.
type PageData struct {
	Keyword string
}

// htmlTemplate is the HTML template for the search results page.
const htmlTemplate = `
<!DOCTYPE html>
<html lang="en">
<head>
    <meta charset="UTF-8">
    <meta name="viewport" content="width=device-width, initial-scale=1.0">
    <title>Product Search Results</title>
    <style>
        body { font-family: sans-serif; margin: 2em; }
        h2 { color: #333; }
        .results-container { margin-top: 20px; }
    </style>
</head>
<body>
    <h2>Search Results: {{.Keyword}}</h2>
    <div class="results-container">
        <!-- Placeholder for actual product results -->
        <p>Displaying results for: <strong>{{.Keyword}}</strong></p>
    </div>
</body>
</html>
`

// HandleProductSearch handles the product search request.
// It retrieves the 'keyword' query parameter and displays it in the page title.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Only allow GET method
	if r.Method != http.MethodGet {
		http.Error(w, "Method not allowed", http.StatusMethodNotAllowed)
		return
	}

	// Retrieve the 'keyword' query parameter
	keyword := r.URL.Query().Get("keyword")

	// Sanitize the keyword to prevent XSS attacks
	// Although html/template handles escaping, we ensure the data is clean
	sanitizedKeyword := html.EscapeString(strings.TrimSpace(keyword))

	// Prepare data for the template
	data := PageData{
		Keyword: sanitizedKeyword,
	}

	// Parse the HTML template
	tmpl, err := template.New("search").Parse(htmlTemplate)
	if err != nil {
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	// Set the content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Execute the template with the data
	if err := tmpl.Execute(w, data); err != nil {
		// Log the error in a real application
		http.Error(w, "Error rendering page", http.StatusInternalServerError)
	}
}

func main() {
	// Register the handler function
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server
	// Using a standard port for local testing
	port := ":8080"
	println("Server starting on http://localhost" + port)
	if err := http.ListenAndServe(port, nil); err != nil {
		panic(err)
	}
}

