    <h2>Search Results: {{.Keyword}}</h2>
    <div class="results-info">
        Displaying results for your search query.
    </div>
</body>
</html>`

// HandleProductSearch handles the product search request.
func HandleProductSearch(w http.ResponseWriter, r *http.Request) {
	// Set the content type to HTML
	w.Header().Set("Content-Type", "text/html; charset=utf-8")

	// Parse the query parameters to get the keyword
	keyword := r.URL.Query().Get("keyword")

	// Sanitize the keyword to prevent XSS (Cross-Site Scripting) attacks.
	// While the template engine handles escaping, it's good practice to normalize input.
	// We trim whitespace to ensure clean display.
	keyword = strings.TrimSpace(keyword)

	// If no keyword is provided, display an empty string (or handle as needed)
	if keyword == "" {
		keyword = ""
	}

	// Create a template object
	tmpl, err := template.New("search").Parse(htmlTemplate)
	if err != nil {
		// In a real application, you might want to log this error.
		// For this implementation, we return a 500 Internal Server Error.
		http.Error(w, "Internal Server Error", http.StatusInternalServerError)
		return
	}

	// Prepare the data for the template
	data := PageData{
		Keyword: html.EscapeString(keyword), // Escape HTML special characters in the keyword
	}

	// Execute the template with the data
	err = tmpl.Execute(w, data)
	if err != nil {
		// Handle execution errors (e.g., connection closed by client)
		// We cannot write headers here, but we can stop execution.
		return
	}
}

func main() {
	// Register the handler function for the /search path
	http.HandleFunc("/search", HandleProductSearch)

	// Start the HTTP server on port 8080
	// Using a standard port for web applications
	err := http.ListenAndServe(":8080", nil)
	if err != nil {
