    htmlBuilder.WriteString("        .keyword { font-weight: bold; color: #007bff; }\n")
    htmlBuilder.WriteString("    </style>\n")
    htmlBuilder.WriteString("</head>\n")
    htmlBuilder.WriteString("<body>\n")

    // Main content: Search Results Title
    htmlBuilder.WriteString("    <h2>Search Results: ")
    htmlBuilder.WriteString(sanitizedKeyword)
    htmlBuilder.WriteString("</h2>\n")

    // Placeholder for actual search results
    htmlBuilder.WriteString("    <div class=\"results\">\n")
    htmlBuilder.WriteString("        <p>Displaying search results for: <span class=\"keyword\">")
    htmlBuilder.WriteString(sanitizedKeyword)
    htmlBuilder.WriteString("</span></p>\n")
    htmlBuilder.WriteString("        <!-- Product results would be listed here -->\n")
    htmlBuilder.WriteString("    </div>\n")

    // Analytics Section
    htmlBuilder.WriteString("    <div class=\"analytics\">\n")
    htmlBuilder.WriteString("        <h3>Analytics Data</h3>\n")
    htmlBuilder.WriteString("        <p><strong>Search Query:</strong> ")
    htmlBuilder.WriteString(sanitizedKeyword)
    htmlBuilder.WriteString("</p>\n")
    htmlBuilder.WriteString("        <p><strong>Timestamp:</strong> ")
    htmlBuilder.WriteString("Current request processed successfully")
    htmlBuilder.WriteString("</p>\n")
    htmlBuilder.WriteString("        <p><strong>Client IP:</strong> ")
    // Extract IP address (handling potential proxies)
    ip := r.RemoteAddr
    if forwardedFor := r.Header.Get("X-Forwarded-For"); forwardedFor != "" {
        ip = forwardedFor
    }
    htmlBuilder.WriteString(html.EscapeString(ip))
    htmlBuilder.WriteString("</p>\n")
    htmlBuilder.WriteString("    </div>\n")

    // End HTML document
    htmlBuilder.WriteString("</body>\n")
    htmlBuilder.WriteString("</html>")

    // Write the response
    w.Write([]byte(htmlBuilder.String()))
}

func main() {
